.card {
  box-sizing: content-box;
  width: 300px;
  padding: 20px;
  border: 10px solid black;
}

.parent { position: relative; z-index: 1; opacity: 0.99; }
.child  { position: relative; z-index: 9999; }  /* inside .parent */
.other  { position: relative; z-index: 2; }        /* sibling of .parent */

body   { font-size: 16px; }
.outer { font-size: 1.5em; }   /* child of body */
.inner { font-size: 1.5em; }   /* child of .outer */
